function validateEmail(email) {
  // Check if the email contains an @ symbol
  if (email.indexOf('@') === -1) {
    return false;
  }

  // Split the email into the local part and domain part
  var parts = email.split('@');
  var localPart = parts[0];
  var domainPart = parts[1];

  // Check if the local part is empty or contains invalid characters
  if (localPart.length === 0 || !isValidLocalPart(localPart)) {
    return false;
  }

  // Check if the domain part is empty or contains invalid characters
  if (domainPart.length === 0 || !isValidDomainPart(domainPart)) {
    return false;
  }

  // Check if the domain part has a valid TLD (top-level domain)
  var tld = domainPart.split('.');
  if (tld.length === 1 || tld[tld.length - 1].length === 0) {
    return false;
  }

  // If all checks pass, the email is valid
  return true;
}

function isValidLocalPart(localPart) {
  // Check if the local part contains any invalid characters
  var invalidChars = ['<', '>', '(', ')', '[', ']', '\\', ',', ';', ':', '\"', '\'', ' '];
  for (var i = 0; i < invalidChars.length; i++) {
    if (localPart.indexOf(invalidChars[i]) !== -1) {
      return false;
    }
  }

  // If no invalid characters are found, the local part is valid
  return true;
}

function isValidDomainPart(domainPart) {
  // Check if the domain part contains any invalid characters
  var invalidChars = ['<', '>', '(', ')', '[', ']', '\\', ',', ';', ':', '\"', '\'', ' '];
  for (var i = 0; i < invalidChars.length; i++) {
    if (domainPart.indexOf(invalidChars[i]) !== -1) {
      return false;
    }
  }

  // If no invalid characters are found, the domain part is valid
  return true;
}
```

