function calculateTriangleArea(side1, side2, side3) {
  // Check if the given lengths can form a triangle
  if (side1 + side2 <= side3 || side1 + side3 <= side2 || side2 + side3 <= side1) {
    return "Not possible to form a triangle with the given side lengths";
  }

  // Find the maximum side length
  const maxSide = Math.max(side1, side2, side3);

  // Calculate the semi-perimeter
  const semiPerimeter = (side1 + side2 + side3) / 2;

  // Calculate the area using Heron's formula
  const area = Math.sqrt(semiPerimeter * (semiPerimeter - side1) * (semiPerimeter - side2) * (semiPerimeter - side3));

  return area;
}

