```python
class Node:
    def __init__(self, value):
        self.value = value
        self.next = None

class Stack:
    def __init__(self):
        self.head = None

    def is_empty(self):
        return self.head is None

    def push(self, value):
        new_node = Node(value)
        if self.is_empty():
            self.head = new_node
        else:
            new_node.next = self.head
            self.head = new_node

    def pop(self):
        if self.is_empty():
            return None
        else:
            popped_value = self.head.value
            self.head = self.head.next
            return popped_value

    def peek(self):
        if self.is_empty():
            return None
        else:
            return self.head.value

    def display(self):
        current = self.head
        stack_elements = []
        while current:
            stack_elements.append(current.value)
            current = current.next
        print(stack_elements)
```

