#include <iostream>

void reverseWords(std::string& str) {
    int n = str.length();

    // Reverse the whole string
    for (int i = 0; i < n / 2; i++)
        std::swap(str[i], str[n - i - 1]);

    int start = 0;
    for (int end = 0; end < n; end++) {
        if (str[end] == ' ') {
            // Reverse the word between start and end-1
            for (int i = start; i < (start + end) / 2; i++)
                std::swap(str[i], str[start + end - i - 1]);
            start = end + 1;
        }
    }

    // Reverse the last word
    for (int i = start; i < (start + n) / 2; i++)
        std::swap(str[i], str[start + n - i - 1]);
}

int main() {
    std::string str;

    // Read the input string with leading/trailing spaces and multiple spaces between words
    std::getline(std::cin, str);

    // Reverse the words while maintaining the original order
    reverseWords(str);

    std::cout << "Reversed string: " << str << std::endl;

    return 0;
}
```

