Here is a Perl script that extracts the first three unique words from a given string, ignoring case sensitivity:

```perl
#!/usr/bin/perl

use strict;
use warnings;

sub extract_unique_words {
    my ($string) = @_;

    # Convert the string to lowercase
    $string = lc $string;

    my %word_count;
    my @words = split(/\s+/, $string);

    foreach my $word (@words) {
        # Remove any punctuation characters from the word
        $word =~ s/[^a-z]//gi;

        # Skip if the word is empty
        next if $word eq '';

        # Increment the word count
        $word_count{$word}++;

        # Break the loop if we have found three unique words
        last if scalar(keys %word_count) >= 3;
    }

    return keys %word_count;
}

# Test the function
my $string = "I love apples, but I also love bananas and apples";
my @unique_words = extract_unique_words($string);

print "Unique words: ";
foreach my $word (@unique_words) {
    print "$word ";
}
print "\n";
```

