Here is a JavaScript program that checks if a string has at least two uppercase alphabets, two lowercase alphabets, two numeric characters, and two special characters:

```javascript
function checkStringValidity(str) {
  // Counters for each category
  let uppercaseCount = 0;
  let lowercaseCount = 0;
  let numericCount = 0;
  let specialCharCount = 0;

  // Regular expressions for each category
  const uppercaseRegex = /[A-Z]/;
  const lowercaseRegex = /[a-z]/;
  const numericRegex = /[0-9]/;
  const specialCharRegex = /[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]/;

  // Iterate over each character in the string
  for (let i = 0; i < str.length; i++) {
    const char = str[i];

    // Check if the character matches any category
    if (uppercaseRegex.test(char)) {
      uppercaseCount++;
    } else if (lowercaseRegex.test(char)) {
      lowercaseCount++;
    } else if (numericRegex.test(char)) {
      numericCount++;
    } else if (specialCharRegex.test(char)) {
      specialCharCount++;
    }
  }

  // Check if all categories have at least two characters
  return (
    uppercaseCount >= 2 &&
    lowercaseCount >= 2 &&
    numericCount >= 2 &&
    specialCharCount >= 2
  );
}

// Test the program
const testString = "AbC12@#$";
console.log(checkStringValidity(testString)); // Output: true
```

