import datetime

class CalendarDate:
    def __init__(self, year, month, day):
        self.year = year
        self.month = month
        self.day = day

    def __str__(self):
        return f"{self.year}-{self.month:02d}-{self.day:02d}"

    def get_weekday(self):
        date = datetime.date(self.year, self.month, self.day)
        return date.strftime("%A")

    def is_leap_year(self):
        if self.year % 4 != 0:
            return False
        elif self.year % 100 != 0:
            return True
        elif self.year % 400 != 0:
            return False
        else:
            return True

    def add_days(self, n):
        date = datetime.date(self.year, self.month, self.day)
        new_date = date + datetime.timedelta(days=n)
        self.year = new_date.year
        self.month = new_date.month
        self.day = new_date.day

    def subtract_days(self, n):
        date = datetime.date(self.year, self.month, self.day)
        new_date = date - datetime.timedelta(days=n)
        self.year = new_date.year
        self.month = new_date.month
        self.day = new_date.day

    def add_months(self, n):
        year = self.year + (self.month + n - 1) // 12
        month = (self.month + n - 1) % 12 + 1
        day = min(self.day, self.last_day_of_month(year, month))
        self.year = year
        self.month = month
        self.day = day

    def subtract_months(self, n):
        year = self.year + (self.month - n - 1) // 12
        month = (self.month - n - 1) % 12 + 1
        day = min(self.day, self.last_day_of_month(year, month))
        self.year = year
        self.month = month
        self.day = day

    def add_years(self, n):
        self.year += n

    def subtract_years(self, n):
        self.year -= n

    def compare_dates(self, date):
        if self.year < date.year:
            return -1
        elif self.year > date.year:
            return 1
        else:
            if self.month < date.month:
                return -1
            elif self.month > date.month:
                return 1
            else:
                if self.day < date.day:
                    return -1
                elif self.day > date.day:
                    return 1
                else:
                    return 0

    def last_day_of_month(self, year, month):
        if month == 2 and self.is_leap_year(year):
            return 29
        elif month == 2:
            return 28
        elif month in [4, 6, 9, 11]:
            return 30
        else:
            return 31
```

The implementation uses the `datetime` module from the Python standard library to handle some of the date-related operations. The `last_day_of_month` method is a helper method that determines the last day of a given month and year, taking leap years into account.

Please note that this implementation assumes the Gregorian calendar system. If you want to support other calendar systems, you may need to modify the implementation accordingly.

