import java.util.Scanner;

public class ReplaceLetter {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Read the input string from the user
        System.out.print("Enter a string: ");
        String inputString = scanner.nextLine();

        // Read the letter to replace from the user
        System.out.print("Enter the letter to replace: ");
        char letterToReplace = scanner.nextLine().charAt(0);

        // Read the replacement letter from the user
        System.out.print("Enter the replacement letter: ");
        char replacementLetter = scanner.nextLine().charAt(0);

        // Replace the letter at the beginning or end of a word
        String result = replaceLetterInWords(inputString, letterToReplace, replacementLetter);

        // Count the number of replacements made
        int numReplacements = countReplacements(inputString, result, letterToReplace);

        // Display the result and the number of replacements
        System.out.println("Result: " + result);
        System.out.println("Number of replacements made: " + numReplacements);

        scanner.close();
    }

    public static String replaceLetterInWords(String inputString, char letterToReplace, char replacementLetter) {
        // Split the input string into words
        String[] words = inputString.split(" ");

        // Replace the letter at the beginning or end of a word with the replacement letter
        for (int i = 0; i < words.length; i++) {
            String word = words[i];
            if (word.length() > 0 && (word.charAt(0) == letterToReplace || word.charAt(word.length() - 1) == letterToReplace)) {
                words[i] = word.replace(letterToReplace, replacementLetter);
            }
        }

        // Join the words back into a single string
        return String.join(" ", words);
    }

    public static int countReplacements(String inputString, String result, char letterToReplace) {
        int count = 0;
        int index = inputString.indexOf(letterToReplace);
        while (index != -1) {
            count++;
            index = inputString.indexOf(letterToReplace, index + 1);
        }
        return count;
    }
}
```

