#include <cmath>

class Point4D {
private:
    double x, y, z, w;

public:
    Point4D(double x, double y, double z, double w) {
        this->x = x;
        this->y = y;
        this->z = z;
        this->w = w;
    }

    double distance(Point4D other) {
        double dx = this->x - other.x;
        double dy = this->y - other.y;
        double dz = this->z - other.z;
        double dw = this->w - other.w;

        return std::sqrt(dx * dx + dy * dy + dz * dz + dw * dw);
    }

    double dotProduct(Point4D other) {
        return this->x * other.x + this->y * other.y + this->z * other.z + this->w * other.w;
    }

    Point4D crossProduct(Point4D other) {
        double newX = this->y * other.z - this->z * other.y;
        double newY = this->z * other.x - this->x * other.z;
        double newZ = this->x * other.y - this->y * other.x;
        double newW = 0; // cross product is not defined in 4D, so setting the w coordinate to 0

        return Point4D(newX, newY, newZ, newW);
    }
};
```

