```javascript
function groupObjectsIntoBunches(array) {
  // Group objects into bunches of 3
  let bunches = [];
  for (let i = 0; i < array.length; i += 3) {
    bunches.push(array.slice(i, i + 3));
  }

  // Sort each bunch in ascending order
  bunches.forEach(bunch => bunch.sort((a, b) => a - b));

  // Sort output array in descending order based on sum of objects in each bunch
  bunches.sort((a, b) => {
    const sumA = a.reduce((acc, val) => acc + val, 0);
    const sumB = b.reduce((acc, val) => acc + val, 0);
    return sumB - sumA;
  });

  return bunches;
}

