```javascript
function areAnagrams(str1, str2) {
  // If the lengths of the strings are different, they can't be anagrams
  if (str1.length !== str2.length) {
    return false;
  }

  // Convert the strings to character arrays
  var arr1 = str1.split('');
  var arr2 = str2.split('');

  // Sort the character arrays using bubble sort
  for (var i = 0; i < arr1.length - 1; i++) {
    for (var j = 0; j < arr1.length - i - 1; j++) {
      if (arr1[j] > arr1[j + 1]) {
        var temp = arr1[j];
        arr1[j] = arr1[j + 1];
        arr1[j + 1] = temp;
      }
      if (arr2[j] > arr2[j + 1]) {
        var temp = arr2[j];
        arr2[j] = arr2[j + 1];
        arr2[j + 1] = temp;
      }
    }
  }

  // Compare the sorted arrays character by character
  for (var k = 0; k < arr1.length; k++) {
    if (arr1[k] !== arr2[k]) {
      return false;
    }
  }

  // If all characters are the same, the strings are anagrams
  return true;
}
```

