function checkProperty(obj, propertyPath, value) {
  // Split the property path into an array of nested properties
  const properties = propertyPath.split('.');

  // Iterate through each nested property
  for (let i = 0; i < properties.length; i++) {
    const property = properties[i];

    // Handle cases where the object or any intermediate property along the path is null or undefined
    if (obj === null || typeof obj !== 'object' || !(property in obj)) {
      return false;
    }

    // Access the nested property
    obj = obj[property];
  }

  // If no value is specified, only check if the property exists
  if (value === undefined) {
    return true;
  }

  // Check if the property is an array and its length matches a specified value
  if (Array.isArray(obj) && /^\d+$/.test(value)) {
    return obj.length === parseInt(value);
  }

  // Check if the property is a function and it returns a specific value
  if (typeof obj === 'function') {
    return obj() === value;
  }

  // Check if the property value matches the specified value
  return obj === value;
}
