function getElementsWithClass(className, parentID) {
  const parentElement = document.getElementById(parentID);
  if (!parentElement) {
    return [];
  }

  const elements = Array.from(parentElement.getElementsByClassName(className));

  const filteredElements = elements.filter((element) => {
    return !(element.hasAttribute('data-ignore') && element.getAttribute('data-ignore') === 'true');
  });

  const sortedElements = filteredElements.sort((a, b) => {
    const aTextContent = a.textContent.trim();
    const bTextContent = b.textContent.trim();
    if (aTextContent < bTextContent) {
      return 1;
    }
    if (aTextContent > bTextContent) {
      return -1;
    }
    return 0;
  });

  return sortedElements;
}
