def trisection_algorithm(f, a, b, epsilon, max_iter):
    # Calculate the values of f(a), f(a + (b - a)/3), f(a + 2*(b - a)/3), and f(b)
    fa = f(a)
    fb = f(b)
    f1 = f(a + (b - a)/3)
    f2 = f(a + 2*(b - a)/3)

    # Check if any of the values are within the tolerance level of zero
    if abs(fa) < epsilon:
        return a
    elif abs(fb) < epsilon:
        return b
    elif abs(f1) < epsilon:
        return a + (b - a)/3
    elif abs(f2) < epsilon:
        return a + 2*(b - a)/3

    # Divide the interval into three equal parts
    interval1 = [a, a + (b - a)/3]
    interval2 = [a + (b - a)/3, a + 2*(b - a)/3]
    interval3 = [a + 2*(b - a)/3, b]

    # Determine which part contains the root
    if fa * f1 < 0:
        new_interval = interval1
    elif f1 * f2 < 0:
        new_interval = interval2
    elif f2 * fb < 0:
        new_interval = interval3
    else:
        raise TrisectionError("Trisection algorithm failed to converge within the maximum number of iterations.")

    # Repeat steps 1-4 with the new interval
    for _ in range(max_iter):
        a, b = new_interval[0], new_interval[1]

        # Calculate the values of f(a), f(a + (b - a)/3), f(a + 2*(b - a)/3), and f(b)
        fa = f(a)
        fb = f(b)
        f1 = f(a + (b - a)/3)
        f2 = f(a + 2*(b - a)/3)

        # Check if any of the values are within the tolerance level of zero
        if abs(fa) < epsilon:
            return a
        elif abs(fb) < epsilon:
            return b
        elif abs(f1) < epsilon:
            return a + (b - a)/3
        elif abs(f2) < epsilon:
            return a + 2*(b - a)/3

        # Divide the interval into three equal parts
        interval1 = [a, a + (b - a)/3]
        interval2 = [a + (b - a)/3, a + 2*(b - a)/3]
        interval3 = [a + 2*(b - a)/3, b]

        # Determine which part contains the root
        if fa * f1 < 0:
            new_interval = interval1
        elif f1 * f2 < 0:
            new_interval = interval2
        elif f2 * fb < 0:
            new_interval = interval3
        else:
            raise TrisectionError("Trisection algorithm failed to converge within the maximum number of iterations.")

    raise TrisectionError("Trisection algorithm failed to converge within the maximum number of iterations.")

