function mergeSort(array, start, end) {
  if (start < end) {
    const mid = Math.floor((start + end) / 2);
    mergeSort(array, start, mid);
    mergeSort(array, mid + 1, end);
    merge(array, start, mid, end);
  }
}

function merge(array, start, mid, end) {
  const leftSize = mid - start + 1;
  const rightSize = end - mid;

  // Create temporary variables to store the left and right subarrays
  let leftSubarray = array.slice(start, mid + 1);
  let rightSubarray = array.slice(mid + 1, end + 1);

  let i = 0; // Index for left subarray
  let j = 0; // Index for right subarray
  let k = start; // Index for the merged array

  // Merge the left and right subarrays in sorted order
  while (i < leftSize && j < rightSize) {
    if (leftSubarray[i] <= rightSubarray[j]) {
      array[k] = leftSubarray[i];
      i++;
    } else {
      array[k] = rightSubarray[j];
      j++;
    }
    k++;
  }

  // Copy any remaining elements from the left subarray
  while (i < leftSize) {
    array[k] = leftSubarray[i];
    i++;
    k++;
  }

  // Copy any remaining elements from the right subarray
  while (j < rightSize) {
    array[k] = rightSubarray[j];
    j++;
    k++;
  }
}

