import java.util.Scanner;

public class BubbleSort {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Prompt the user to enter the size of the array
        System.out.print("Enter the size of the array: ");
        int size = scanner.nextInt();

        // Validate the input
        if (size < 10) {
            System.out.println("Size of the array must be a positive integer greater than or equal to 10.");
            return;
        }

        int[] array = new int[size];

        // Prompt the user to enter the elements of the array
        System.out.println("Enter the elements of the array:");
        for (int i = 0; i < size; i++) {
            System.out.print("Element " + (i + 1) + ": ");
            try {
                int element = scanner.nextInt();
                // Validate the input
                if (element < -100 || element > 100) {
                    System.out.println("Each element must be an integer within the range of -100 to 100 (inclusive).");
                    return;
                }
                array[i] = element;
            } catch (Exception e) {
                System.out.println("Invalid input. Each element must be an integer.");
                return;
            }
        }

        // Bubble sort algorithm
        for (int i = 0; i < size - 1; i++) {
            for (int j = 0; j < size - i - 1; j++) {
                if (array[j] > array[j + 1]) {
                    // Swap adjacent elements if they are in the wrong order
                    int temp = array[j];
                    array[j] = array[j + 1];
                    array[j + 1] = temp;
                }
            }
        }

        // Display the sorted array
        System.out.print("Sorted array: ");
        for (int i = 0; i < size; i++) {
            System.out.print(array[i] + " ");
        }
        System.out.println();

        // Calculate the average of the sorted array
        int sum = 0;
        for (int i = 0; i < size; i++) {
            sum += array[i];
        }
        double average = (double) sum / size;
        System.out.println("Average of the sorted array: " + average);

        // Binary search algorithm
        System.out.print("Enter the element to search for: ");
        int searchElement = scanner.nextInt();

        int low = 0;
        int high = size - 1;
        boolean found = false;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (array[mid] == searchElement) {
                found = true;
                break;
            } else if (array[mid] < searchElement) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        if (found) {
            System.out.println("Element found in the sorted array.");
        } else {
            System.out.println("Element not found in the sorted array.");
        }

        // Reverse the sorted array
        for (int i = 0; i < size / 2; i++) {
            int temp = array[i];
            array[i] = array[size - 1 - i];
            array[size - 1 - i] = temp;
        }

        // Display the reversed array
        System.out.print("Reversed array: ");
        for (int i = 0; i < size; i++) {
            System.out.print(array[i] + " ");
        }
