function isPrime(num) {
  if (num <= 1) return false;
  if (num <= 3) return true;

  if (num % 2 === 0 || num % 3 === 0) return false;

  for (let i = 5; i * i <= num; i += 6) {
    if (num % i === 0 || num % (i + 2) === 0) return false;
  }

  return true;
}

function isPalindromicBinary(num) {
  const binary = num.toString(2);
  return binary === binary.split('').reverse().join('');
}

function findPalindromicPrimes(count) {
  let found = 0;
  let num = 2;
  const palindromicPrimes = [];

  while (found < count) {
    if (isPrime(num) && isPalindromicBinary(num)) {
      palindromicPrimes.push(num);
      found++;
    }
    num++;
  }

  return palindromicPrimes;
}

