import java.util.ArrayList;
import java.util.List;

public class SmallestCommonDenominator {
    public static void main(String[] args) {
        List<Pair> pairs = new ArrayList<>();
        pairs.add(new Pair(14, 28));
        pairs.add(new Pair(21, 35));

        for (Pair pair : pairs) {
            int smallestCommonDenominator = findSmallestCommonDenominator(pair.a, pair.b);
            List<Integer> primeFactors = findPrimeFactors(smallestCommonDenominator);

            System.out.println("For the pair (" + pair.a + ", " + pair.b + "):");
            System.out.println("The smallest common denominator is " + smallestCommonDenominator + " and its prime factors are " + primeFactors);
        }
    }

    private static int findSmallestCommonDenominator(int a, int b) {
        int gcd = findGCD(a, b);
        return a * (b / gcd);
    }

    private static int findGCD(int a, int b) {
        if (b == 0) {
            return a;
        }
        return findGCD(b, a % b);
    }

    private static List<Integer> findPrimeFactors(int n) {
        List<Integer> primeFactors = new ArrayList<>();
        int divisor = 2;

        while (n > 1) {
            if (n % divisor == 0) {
                primeFactors.add(divisor);
                n /= divisor;
            } else {
                divisor++;
            }
        }

        return primeFactors;
    }

    static class Pair {
        int a;
        int b;

        public Pair(int a, int b) {
            this.a = a;
            this.b = b;
        }
    }
}
```

This program uses the Euclidean algorithm to find the greatest common divisor (GCD) of the two input numbers. Then, it calculates the smallest common denominator by multiplying the two input numbers and dividing by their GCD. The prime factors of the smallest common denominator are found using a simple algorithm that repeatedly divides the number by increasing divisors until it is reduced to 1.

