Here's a C++ program that calculates the difference between two dates and handles different time zones and daylight saving time changes:

```cpp
#include <iostream>
#include <ctime>

bool isValidDate(int day, int month, int year) {
    // Check if the date is valid
    if (year < 1900 || year > 3000 || month < 1 || month > 12 || day < 1 || day > 31) {
        return false;
    }

    // Check if the month has correct number of days
    int daysInMonth[] = {31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31};
    if (month == 2 && (year % 4 == 0 && (year % 100 != 0 || year % 400 == 0))) {
        daysInMonth[1] = 29; // Leap year
    }

    return day <= daysInMonth[month - 1];
}

int main() {
    int day1, month1, year1, day2, month2, year2;
    int hour1, minute1, second1, hour2, minute2, second2;
    int timeZone1, timeZone2;

    // Get the first date
    std::cout << "Enter the first date (dd mm yyyy): ";
    std::cin >> day1 >> month1 >> year1;

    // Check if the first date is valid
    if (!isValidDate(day1, month1, year1)) {
        std::cout << "Invalid date!" << std::endl;
        return 0;
    }

    // Get the time zone for the first date
    std::cout << "Enter the time zone for the first date (+/- hours): ";
    std::cin >> timeZone1;

    // Get the second date
    std::cout << "Enter the second date (dd mm yyyy): ";
    std::cin >> day2 >> month2 >> year2;

    // Check if the second date is valid
    if (!isValidDate(day2, month2, year2)) {
        std::cout << "Invalid date!" << std::endl;
        return 0;
    }

    // Get the time zone for the second date
    std::cout << "Enter the time zone for the second date (+/- hours): ";
    std::cin >> timeZone2;

    // Get the time for the first date
    std::cout << "Enter the time for the first date (hh:mm:ss): ";
    std::cin >> hour1 >> minute1 >> second1;

    // Get the time for the second date
    std::cout << "Enter the time for the second date (hh:mm:ss): ";
    std::cin >> hour2 >> minute2 >> second2;

    // Convert the dates to time_t objects
    struct std::tm time1 = {0};
    time1.tm_year = year1 - 1900;
    time1.tm_mon = month1 - 1;
    time1.tm_mday = day1;
    time1.tm_hour = hour1;
    time1.tm_min = minute1;
    time1.tm_sec = second1;

    struct std::tm time2 = {0};
    time2.tm_year = year2 - 1900;
    time2.tm_mon = month2 - 1;
    time2.tm_mday = day2;
    time2.tm_hour = hour2;
    time2.tm_min = minute2;
    time2.tm_sec = second2;

    // Adjust the time according to time zones
    time1.tm_hour -= timeZone1;
    time2.tm_hour -= timeZone2;

    // Convert the time_t objects to time since epoch
    std::time_t t1 = std::mktime(&time1);
    std::time_t t2 = std::mktime(&time2);

    // Calculate the difference between the two times
    double difference = std::difftime(t2, t1);

    // Display the difference
    std::cout << "Difference between the two dates: " << difference << " seconds" << std::endl;

    return 0;
