Here is a method that generates a random password with the specified number of characters, ensuring that it contains at least one uppercase letter, one lowercase letter, one digit, and one special character:

```java
import java.util.ArrayList;
import java.util.List;
import java.util.Random;

public class PasswordGenerator {

    private static final String LOWER_CASE = "abcdefghijklmnopqrstuvwxyz";
    private static final String UPPER_CASE = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    private static final String DIGITS = "0123456789";
    private static final String SPECIAL_CHARACTERS = "!@#$%^&*()_-+=<>?";

    public static String generatePassword(int length) {
        if (length < 4) {
            throw new IllegalArgumentException("Password length must be at least 4 characters.");
        }

        Random random = new Random();
        List<Character> password = new ArrayList<>();

        // Add at least one uppercase letter
        password.add(UPPER_CASE.charAt(random.nextInt(UPPER_CASE.length())));
        // Add at least one lowercase letter
        password.add(LOWER_CASE.charAt(random.nextInt(LOWER_CASE.length())));
        // Add at least one digit
        password.add(DIGITS.charAt(random.nextInt(DIGITS.length())));
        // Add at least one special character
        password.add(SPECIAL_CHARACTERS.charAt(random.nextInt(SPECIAL_CHARACTERS.length())));

        // Fill the remaining characters randomly
        for (int i = 4; i < length; i++) {
            String characters = LOWER_CASE + UPPER_CASE + DIGITS + SPECIAL_CHARACTERS;
            password.add(characters.charAt(random.nextInt(characters.length())));
        }

        // Shuffle the characters to ensure random positions of the required characters
        for (int i = length - 1; i > 0; i--) {
            int j = random.nextInt(i + 1);
            char temp = password.get(i);
            password.set(i, password.get(j));
            password.set(j, temp);
        }

        StringBuilder passwordString = new StringBuilder(password.size());
        for (Character character : password) {
            passwordString.append(character);
        }
        return passwordString.toString();
    }

    public static void main(String[] args) {
        int passwordLength = 8;
        String password = generatePassword(passwordLength);
        System.out.println("Generated Password: " + password);
    }
}
```

