function calculateFactorial(number) {
  if (typeof number !== 'number' || isNaN(number)) {
    throw new Error('Input is not a valid number');
  }

  if (number < 0) {
    throw new Error('Factorial cannot be calculated for negative numbers');
  }

  const roundedNumber = Math.floor(number);

  if (roundedNumber !== number) {
    console.warn('Input is not an integer. Rounding down to the nearest integer...');
  }

  if (isPrime(roundedNumber)) {
    throw new Error('Factorial cannot be calculated for prime numbers');
  }

  let factorial = 1;

  for (let i = 2; i <= roundedNumber; i++) {
    factorial *= i;
  }

  return factorial;
}

function isPrime(number) {
  if (number < 2) {
    return false;
  }

  for (let i = 2; i < number; i++) {
    if (number % i === 0) {
      return false;
    }
  }

  return true;
}
