using System;

public class NarcissisticNumber
{
    public static bool IsNarcissisticNumber(string number)
    {
        if (string.IsNullOrEmpty(number))
        {
            throw new ArgumentException("Invalid input. The number cannot be null or empty.");
        }

        if (!long.TryParse(number, out long n))
        {
            throw new ArgumentException("Invalid input. The number must be a numeric value.");
        }

        if (n < 0)
        {
            return false;
        }

        int digitCount = number.Length;
        if (!IsPrime(digitCount))
        {
            return false;
        }

        long sum = 0;
        long temp = n;
        while (temp != 0)
        {
            int digit = (int)(temp % 10);
            sum += Power(digit, digitCount);
            temp /= 10;
        }

        return sum == n;
    }

    private static bool IsPrime(int number)
    {
        if (number < 2)
        {
            return false;
        }

        for (int i = 2; i <= Math.Sqrt(number); i++)
        {
            if (number % i == 0)
            {
                return false;
            }
        }

        return true;
    }

    private static long Power(int baseValue, int exponent)
    {
        long result = 1;
        for (int i = 0; i < exponent; i++)
        {
            result *= baseValue;
        }

        return result;
    }
}
