    // Find the maximum number in the input array
    let maxNum = nums.max()!

    // Generate all prime numbers up to maxNum using Sieve of Eratosthenes
    var primes = [Bool](repeating: true, count: maxNum + 1)
    primes[0] = false
    primes[1] = false

    var p = 2
    while p * p <= maxNum {
        if primes[p] {
            var i = p * p
            while i <= maxNum {
                primes[i] = false
                i += p
            }
        }
        p += 1
    }

    // Loop through the input array and check if each number is prime
    var result: [Int] = []
    for num in nums {
        if num >= 2 && primes[num] {
            // Check for duplicates in the result array
            if !result.contains(num) {
                result.append(num)
            }
        }
    }

    return result
}
