import java.math.BigDecimal;
import java.math.BigInteger;
import java.math.MathContext;
import java.math.RoundingMode;
import java.util.ArrayList;
import java.util.List;

public class ScientificCalculator {
    private List<String> history;
    private MathContext mathContext;

    public ScientificCalculator() {
        history = new ArrayList<>();
        mathContext = new MathContext(100, RoundingMode.HALF_UP);
    }

    public void add(BigDecimal num1, BigDecimal num2) {
        BigDecimal result = num1.add(num2, mathContext);
        history.add(num1 + " + " + num2 + " = " + result);
        System.out.println(result);
    }

    public void subtract(BigDecimal num1, BigDecimal num2) {
        BigDecimal result = num1.subtract(num2, mathContext);
        history.add(num1 + " - " + num2 + " = " + result);
        System.out.println(result);
    }

    public void multiply(BigDecimal num1, BigDecimal num2) {
        BigDecimal result = num1.multiply(num2, mathContext);
        history.add(num1 + " * " + num2 + " = " + result);
        System.out.println(result);
    }

    public void divide(BigDecimal num1, BigDecimal num2) {
        if (num2.equals(BigDecimal.ZERO)) {
            System.out.println("Error: Division by zero");
            return;
        }
        BigDecimal result = num1.divide(num2, mathContext);
        history.add(num1 + " / " + num2 + " = " + result);
        System.out.println(result);
    }

    public void squareRoot(BigDecimal num) {
        if (num.compareTo(BigDecimal.ZERO) < 0) {
            System.out.println("Error: Square root of a negative number");
            return;
        }
        BigDecimal result = num.sqrt(mathContext);
        history.add("sqrt(" + num + ") = " + result);
        System.out.println(result);
    }

    public void logarithm(BigDecimal num) {
        if (num.compareTo(BigDecimal.ZERO) <= 0) {
            System.out.println("Error: Logarithm of a non-positive number");
            return;
        }
        BigDecimal result = num.log(mathContext);
        history.add("log(" + num + ") = " + result);
        System.out.println(result);
    }

    public void exponentiate(BigDecimal base, BigDecimal exponent) {
        BigDecimal result = base.pow(exponent.intValue(), mathContext);
        history.add(base + "^" + exponent + " = " + result);
        System.out.println(result);
    }

    public void factorial(BigInteger num) {
        if (num.compareTo(BigInteger.ZERO) < 0) {
            System.out.println("Error: Factorial of a negative number");
            return;
        }
        BigInteger result = BigInteger.ONE;
        for (BigInteger i = BigInteger.ONE; i.compareTo(num) <= 0; i = i.add(BigInteger.ONE)) {
            result = result.multiply(i);
        }
        history.add(num + "! = " + result);
        System.out.println(result);
    }

    public void displayHistory() {
        for (String calculation : history) {
            System.out.println(calculation);
        }
    }

    public static void main(String[] args) {
        ScientificCalculator calculator = new ScientificCalculator();

        calculator.add(new BigDecimal("12345678901234567890"), new BigDecimal("98765432109876543210"));
        calculator.subtract(new BigDecimal("98765432109876543210"), new BigDecimal("12345678901234567890"));
        calculator.multiply(new BigDecimal("12345678901234567890"), new BigDecimal("98765432109876543210"));
