        calculator.squareRoot(new BigDecimal("12345678901234567890"));
        calculator.logarithm(new BigDecimal("12345678901234567890"));
        calculator.exponentiate(new BigDecimal("2"), new BigDecimal("100"));
        calculator.factorial(new BigInteger("100"));

        calculator.displayHistory();
    }
}
