Below is an example implementation of the Caesar Cipher algorithm in Python:

```python
import random

class CaesarCipher:
    def __init__(self, shift_range=(-100, 100)):
        self.shift_range = shift_range
        self.shift_value = 0
        self.secondary_shift_values = {}

    def generate_random_shift(self):
        self.shift_value = random.randint(self.shift_range[0], self.shift_range[1])

    def set_shift_value(self, shift_value):
        self.shift_value = shift_value

    def set_secondary_shift_values(self, secondary_shift_values):
        self.secondary_shift_values = secondary_shift_values

    def encrypt(self, message):
        encrypted_message = ""
        for char in message:
            char_code = ord(char)
            if char_code in self.secondary_shift_values:
                shift = self.secondary_shift_values[char_code]
            else:
                shift = self.shift_value

            if char.isalpha():
                if char.isupper():
                    char_code = (char_code - 65 + shift) % 26 + 65
                else:
                    char_code = (char_code - 97 + shift) % 26 + 97
            else:
                char_code = (char_code + shift) % 128

            encrypted_message += chr(char_code)

        return encrypted_message

    def decrypt(self, encrypted_message):
        decrypted_message = ""
        for char in encrypted_message:
            char_code = ord(char)
            if char_code in self.secondary_shift_values:
                shift = self.secondary_shift_values[char_code]
            else:
                shift = self.shift_value

            if char.isalpha():
                if char.isupper():
                    char_code = (char_code - 65 - shift) % 26 + 65
                else:
                    char_code = (char_code - 97 - shift) % 26 + 97
            else:
                char_code = (char_code - shift) % 128

            decrypted_message += chr(char_code)

        return decrypted_message
```

