// Recursive function to check if a given string is a palindrome
bool isPalindrome(char str[], int start, int end) {
    // Base case: if start and end meet or cross each other, it is a palindrome
    if (start >= end) {
        return true;
    }

    // Ignore non-alphanumeric characters and convert to lowercase
    while (!isalnum(str[start])) {
        start++;
    }
    while (!isalnum(str[end])) {
        end--;
    }
    str[start] = tolower(str[start]);
    str[end] = tolower(str[end]);

    // Check if the characters at start and end are equal
    if (str[start] != str[end]) {
        return false;
    }

    // Recursively check the remaining substring
    return isPalindrome(str, start + 1, end - 1);
}

int main() {
    char str[1000000];
    printf("Enter a string: ");
    fgets(str, sizeof(str), stdin);

    // Check if the given string is a palindrome
    if (isPalindrome(str, 0, strlen(str) - 1)) {
        printf("The string is a palindrome.\n");
    } else {
        printf("The string is not a palindrome.\n");
    }

    return 0;
}
```
