To convert an XML document to a dictionary, we can use a stack-based approach. We will iterate over each character in the XML document and keep track of the current element and its attributes as we traverse the document.

Here is the implementation in Python:

```python
def xml_to_dict(xml):
    stack = []
    result = {}
    current = result

    i = 0
    while i < len(xml):
        if xml[i] == '<':
            if xml[i+1] == '/':
                # closing tag
                i += 2
                tag_name = ''
                while xml[i] != '>':
                    tag_name += xml[i]
                    i += 1
                i += 1
                if stack:
                    current = stack.pop()
            else:
                # opening tag
                i += 1
                tag_name = ''
                while xml[i] != '>' and xml[i] != ' ':
                    tag_name += xml[i]
                    i += 1
                if tag_name not in current:
                    current[tag_name] = {}
                stack.append(current)
                current = current[tag_name]
        elif xml[i] == '>':
            i += 1
        elif xml[i] == ' ':
            i += 1
            attr_name = ''
            attr_value = ''
            while xml[i] != '=':
                attr_name += xml[i]
                i += 1
            i += 2  # skip the '=' and the opening quote
            quote = xml[i]
            i += 1
            while xml[i] != quote:
                attr_value += xml[i]
                i += 1
            i += 1  # skip the closing quote
            current[attr_name] = attr_value
    return result
