import socket
import ssl

def make_http_request(url):
    # Extract the domain and path from the URL
    domain, path = extract_domain_and_path(url)

    # Connect to the server
    context = ssl.create_default_context()
    with socket.create_connection((domain, 443)) as sock:
        with context.wrap_socket(sock, server_hostname=domain) as ssock:
            # Send the HTTP request
            request = f"GET {path} HTTP/1.1\r\nHost: {domain}\r\n\r\n"
            ssock.sendall(request.encode())

            # Receive the response
            response = b""
            while True:
                data = ssock.recv(4096)
                if not data:
                    break
                response += data

    return response.decode()

def extract_domain_and_path(url):
    # Remove the "http://" or "https://" from the URL
    if url.startswith("http://"):
        url = url[len("http://"):]
    elif url.startswith("https://"):
        url = url[len("https://"):]

    # Split the URL into domain and path
    parts = url.split("/", 1)
    domain = parts[0]
    path = "/" + parts[1] if len(parts) > 1 else "/"

    return domain, path

def extract_title(html):
    # Find the start and end indices of the <title> tag
    start_index = html.find("<title>")
    end_index = html.find("</title>")

    # Extract the title text
    if start_index != -1 and end_index != -1:
        title = html[start_index + len("<title>"):end_index]
        return title.strip()

    return None

def extract_meta_description(html):
    # Find the start and end indices of the <meta name="description"> tag
    start_index = html.find('<meta name="description"')
    end_index = html.find(">", start_index)

    # Extract the content attribute value
    if start_index != -1 and end_index != -1:
        content_start = html.find('content="', start_index, end_index) + len('content="')
        content_end = html.find('"', content_start)
        description = html[content_start:content_end]
        return description.strip()

    return None

def display_error_message(error):
    print(f"An error occurred: {error}")

def main():
    url = 'https://example.com'

    try:
        html = make_http_request(url)
        title = extract_title(html)
        meta_description = extract_meta_description(html)

        if title:
            print(f"Title: {title}")
        else:
            print("Title not found")

        if meta_description:
            print(f"Meta Description: {meta_description}")
        else:
            print("Meta Description not found")
    except ConnectionError:
        display_error_message("Unable to connect to the server")
    except ssl.SSLError:
        display_error_message("SSL error occurred")
    except socket.timeout:
        display_error_message("Connection timed out")
    except ValueError:
        display_error_message("Invalid URL")
    except Exception as e:
        display_error_message(str(e))

if __name__ == "__main__":
    main()

