Here's a JavaScript function that converts a date string of the form "DD/MM/YYYY" to the desired format "Weekday, Month dd yyyy":

```javascript
function convertDateFormat(dateString) {
  // Split the date string into day, month, and year
  const parts = dateString.split('/');

  // Validate the date format
  if (parts.length !== 3 || parts[0].length !== 2 || parts[1].length !== 2 || parts[2].length !== 4) {
    return 'Invalid date format';
  }

  // Extract day, month, and year values
  const day = parseInt(parts[0], 10);
  const month = parseInt(parts[1], 10);
  const year = parseInt(parts[2], 10);

  // Validate the day, month, and year values
  if (isNaN(day) || isNaN(month) || isNaN(year) || day > 31 || month > 12 || year < 1900 || year > 2099) {
    return 'Invalid date';
  }

  // Create a new Date object
  const date = new Date(year, month - 1, day);

  // Check if the date is valid
  if (isNaN(date.getTime())) {
    return 'Invalid date';
  }

  // Get the weekday, month, and year in the desired format
  const weekdays = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  const weekday = weekdays[date.getDay()];
  const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
  const monthName = monthNames[date.getMonth()];
  const formattedDate = `${weekday}, ${monthName} ${day} ${year}`;

  return formattedDate;
}

// Example usage
const dateString = '14/08/2020';
console.log(convertDateFormat(dateString)); // Output: "Friday, August 14 2020"
