```html
<!DOCTYPE html>
<html>
<head>
    <title>Prime Factorial Calculator</title>
    <script>
        function calculateFactorial() {
            var number = document.getElementById("number").value;
            var result = document.getElementById("result");
            var errorMessage = document.getElementById("errorMessage");

            if (isNaN(number) || number < 1 || number > 1000 || !isPrime(number)) {
                errorMessage.innerHTML = "Invalid number. Please enter a prime number between 1 and 1000.";
                result.innerHTML = "";
            } else {
                errorMessage.innerHTML = "";
                result.innerHTML = "The factorial of " + number + " is " + factorial(number);
            }
        }

        function isPrime(number) {
            if (number === 1) {
                return false;
            }

            for (var i = 2; i <= Math.sqrt(number); i++) {
                if (number % i === 0) {
                    return false;
                }
            }

            return true;
        }

        function factorial(number) {
            if (number === 0 || number === 1) {
                return 1;
            } else {
                return number * factorial(number - 1);
            }
        }
    </script>
</head>
<body>
    <h1>Prime Factorial Calculator</h1>
    <form>
        <label for="number">Enter a prime number (1-1000):</label>
        <input type="text" id="number" name="number" required>
        <button type="button" onclick="calculateFactorial()">Calculate Factorial</button>
    </form>
    <div id="errorMessage"></div>
    <div id="result"></div>
</body>
</html>
