import pickle

class DataStorage:
    def __init__(self):
        self.data = []

    def add_data(self, value):
        self.data.append(value)

    def perform_arithmetic(self, operation):
        if len(self.data) < 2:
            raise ValueError("Insufficient data for arithmetic operation")

        if operation == "addition":
            result = self.data[0]
            for value in self.data[1:]:
                result += value
            return result
        elif operation == "subtraction":
            result = self.data[0]
            for value in self.data[1:]:
                result -= value
            return result
        elif operation == "multiplication":
            result = self.data[0]
            for value in self.data[1:]:
                result *= value
            return result
        elif operation == "division":
            result = self.data[0]
            for value in self.data[1:]:
                result /= value
            return result
        else:
            raise ValueError("Invalid arithmetic operation")

    def compare_values(self):
        if len(self.data) < 2:
            raise ValueError("Insufficient data for comparison")

        result = True
        for i in range(len(self.data)-1):
            if self.data[i] != self.data[i+1]:
                result = False
                break

        return result

    def get_max_min_values(self):
        if len(self.data) == 0:
            raise ValueError("No data stored")

        max_value = self.data[0]
        min_value = self.data[0]
        for value in self.data[1:]:
            if value > max_value:
                max_value = value
            if value < min_value:
                min_value = value

        return max_value, min_value

    def perform_bitwise_operation(self, operation):
        if len(self.data) < 2:
            raise ValueError("Insufficient data for bitwise operation")

        if operation == "AND":
            result = self.data[0]
            for value in self.data[1:]:
                result &= value
            return result
        elif operation == "OR":
            result = self.data[0]
            for value in self.data[1:]:
                result |= value
            return result
        elif operation == "XOR":
            result = self.data[0]
            for value in self.data[1:]:
                result ^= value
            return result
        else:
            raise ValueError("Invalid bitwise operation")

    def convert_to_type(self, data_type):
        if len(self.data) == 0:
            raise ValueError("No data stored")

        converted_values = []
        for value in self.data:
            try:
                converted_value = data_type(value)
                converted_values.append(converted_value)
            except:
                raise ValueError("Cannot convert to the specified data type")

        return converted_values

    def serialize_to_file(self, file_path):
        if len(self.data) == 0:
            raise ValueError("No data stored")

        with open(file_path, 'wb') as file:
            pickle.dump(self.data, file)

    def deserialize_from_file(self, file_path):
        with open(file_path, 'rb') as file:
            self.data = pickle.load(file)
