Here's a JavaScript program that deep clones an object, converts all properties to uppercase, sorts them in descending order, and deeply clones any nested objects:

```javascript
function deepClone(obj) {
  // Create an empty object to store the cloned object
  const clonedObj = {};

  // Loop through all properties of the original object
  for (let key in obj) {
    // Check if the current property is an object and needs to be deeply cloned
    if (typeof obj[key] === "object" && obj[key] !== null) {
      // Deep clone the nested object and assign it to the cloned object
      clonedObj[key.toUpperCase()] = deepClone(obj[key]);
    } else {
      // Convert the property to uppercase and assign it to the cloned object
      clonedObj[key.toUpperCase()] = obj[key];
    }
  }

  // Sort the properties of the cloned object in descending order
  const sortedKeys = Object.keys(clonedObj).sort().reverse();
  const sortedObj = {};
  sortedKeys.forEach(key => {
    sortedObj[key] = clonedObj[key];
  });

  return sortedObj;
}

// Example usage:
const originalObj = {
  name: "John",
  age: 30,
  address: {
    city: "New York",
    country: "USA"
  }
};

const clonedObj = deepClone(originalObj);
console.log(clonedObj);
```

