```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

int main() {
    std::vector<std::string> names = {"JOHN", "ALICE", "ROBERT", "CHRISTINE", "ALEXANDER", "SAMANTHA"};

    std::transform(names.begin(), names.end(), names.begin(), [](std::string& name) {
        // Convert the name to uppercase
        std::transform(name.begin(), name.end(), name.begin(), ::toupper);

        // Ensure minimum length of 8 characters
        if (name.length() < 8) {
            name += "X"; // Append "X" to make it at least 8 characters long
        }

        return name;
    });

    std::sort(names.begin(), names.end(), [](const std::string& a, const std::string& b) {
        return a.length() < b.length();
    });

    std::vector<std::string> tenCharacterNames;
    std::copy_if(names.begin(), names.end(), std::back_inserter(tenCharacterNames), [](const std::string& name) {
        return name.length() == 10;
    });

    // Print the names with exactly 10 characters
    for (const auto& name : tenCharacterNames) {
        std::cout << name << std::endl;
    }

    return 0;
}
