        this.courses.add(course);
        this.grades.add(grade);
        this.credits.add(credits);
    }

    public void removeCourse(String course) {
        int index = this.courses.indexOf(course);
        if (index != -1) {
            this.courses.remove(index);
            this.grades.remove(index);
            this.credits.remove(index);
        }
    }

    public int calculateAge() {
        LocalDate currentDate = LocalDate.now();
        int age = currentDate.getYear() - this.dateOfBirth.getYear();
        if (currentDate.getMonthValue() < this.dateOfBirth.getMonthValue()
                || (currentDate.getMonthValue() == this.dateOfBirth.getMonthValue()
                && currentDate.getDayOfMonth() < this.dateOfBirth.getDayOfMonth())) {
            age--;
        }
        return age;
    }

    public double calculateGpa() {
        double totalGradePoints = 0;
        int totalCredits = 0;
        for (int i = 0; i < this.courses.size(); i++) {
            String grade = this.grades.get(i);
            int credits = this.credits.get(i);
            totalGradePoints += convertGradeToPoints(grade) * credits;
            totalCredits += credits;
        }
        return totalGradePoints / totalCredits;
