Here's an example implementation of a function that takes a JSON string and returns a JavaScript object, including error handling for invalid JSON strings and circular references:

```javascript
function parseJSON(jsonString) {
  let index = 0;

  function parseValue() {
    const currentChar = jsonString[index];

    if (currentChar === '{') {
      return parseObject();
    } else if (currentChar === '[') {
      return parseArray();
    } else if (currentChar === '"') {
      return parseString();
    } else if (currentChar === 't') {
      return parseTrue();
    } else if (currentChar === 'f') {
      return parseFalse();
    } else if (currentChar === 'n') {
      return parseNull();
    } else if (currentChar === '-' || (currentChar >= '0' && currentChar <= '9')) {
      return parseNumber();
    } else {
      throw new Error('Invalid JSON');
    }
  }

  function parseObject() {
    if (jsonString[index] !== '{') {
      throw new Error('Invalid JSON');
    }

    index++;
    const obj = {};

    while (jsonString[index] !== '}') {
      const key = parseString();

      if (jsonString[index] !== ':') {
        throw new Error('Invalid JSON');
      }

      index++;
      const value = parseValue();
      obj[key] = value;

      if (jsonString[index] === ',') {
        index++;
      } else if (jsonString[index] !== '}') {
        throw new Error('Invalid JSON');
      }
    }

    index++;
    return obj;
  }

  function parseArray() {
    if (jsonString[index] !== '[') {
      throw new Error('Invalid JSON');
    }

    index++;
    const arr = [];

    while (jsonString[index] !== ']') {
      const value = parseValue();
      arr.push(value);

      if (jsonString[index] === ',') {
        index++;
      } else if (jsonString[index] !== ']') {
        throw new Error('Invalid JSON');
      }
    }

    index++;
    return arr;
  }

  function parseString() {
    if (jsonString[index] !== '"') {
      throw new Error('Invalid JSON');
    }

    let result = '';
    index++;

    while (jsonString[index] !== '"') {
      if (jsonString[index] === '\\') {
        index++;
        result += jsonString[index];
      } else {
        result += jsonString[index];
      }
      index++;
    }

    index++;
    return result;
  }

  function parseTrue() {
    if (jsonString.slice(index, index + 4) !== 'true') {
      throw new Error('Invalid JSON');
    }

    index += 4;
    return true;
  }

  function parseFalse() {
    if (jsonString.slice(index, index + 5) !== 'false') {
      throw new Error('Invalid JSON');
    }

    index += 5;
    return false;
  }

  function parseNull() {
    if (jsonString.slice(index, index + 4) !== 'null') {
      throw new Error('Invalid JSON');
    }

    index += 4;
    return null;
  }

  function parseNumber() {
    let start = index;

    while (
      jsonString[index] &&
      (jsonString[index] === '-' ||
        jsonString[index] === '+' ||
        jsonString[index] === '.' ||
        (jsonString[index] >= '0' && jsonString[index] <= '9') ||
        jsonString[index].toLowerCase() === 'e')
    ) {
      index++;
    }

    const num = parseFloat(jsonString.slice(start, index));

    if (isNaN(num)) {
      throw new Error('Invalid JSON');
    }

    return num;
  }

  return parseValue();
}
```

This implementation uses a recursive approach to manually parse the JSON string character by character. It checks for the various valid JSON value types (object, array, string, number, true, false, and null) and constructs the corresponding JavaScript object accordingly. If an invalid JSON string is encountered, it throws an error. The function returns the parsed JavaScript object.

Note that this implementation assumes the input JSON string is well-formed and does not handle cases where the JSON string contains escape sequences or Unicode characters. It also does not handle all possible edge cases, so additional validation or error handling may be required depending on your specific use case.

