function reverseArray(arr) {
  if (!Array.isArray(arr)) {
    throw new Error("Invalid input! The input should be an array.");
  }

  if (arr.length === 0) {
    return arr;
  }

  for (let i = 0; i < Math.floor(arr.length / 2); i++) {
    if (typeof arr[i] !== "number" || typeof arr[arr.length - i - 1] !== "number") {
      throw new Error("Invalid input! The input array should only contain integers.");
    }
    let temp = arr[i];
    arr[i] = arr[arr.length - i - 1];
    arr[arr.length - i - 1] = temp;
  }

  return arr;
}

