def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def miller_rabin(n, k=5):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0:
        return False

    r, s = 0, n - 1
    while s % 2 == 0:
        r += 1
        s //= 2

    for _ in range(k):
        a = random.randrange(2, n - 1)
        x = pow(a, s, n)
        if x == 1 or x == n - 1:
            continue
        for _ in range(r - 1):
            x = pow(x, 2, n)
            if x == n - 1:
                break
        else:
            return False
    return True

def generate_prime_numbers(start, end):
    prime_numbers = []
    for i in range(start, end+1):
        if miller_rabin(i):
            prime_numbers.append(i)
    return prime_numbers

def generate_prime_numbers_multithreaded(start, end, num_threads):
    prime_numbers = []
    step = (end - start + 1) // num_threads
    threads = []

    for i in range(num_threads):
        thread_start = start + i * step
        thread_end = thread_start + step - 1 if i < num_threads - 1 else end
        thread = threading.Thread(target=lambda: prime_numbers.extend(generate_prime_numbers(thread_start, thread_end)))
        thread.start()
        threads.append(thread)

    for thread in threads:
        thread.join()

    return prime_numbers

