    for i in range(len(string) - 3):
        for j in range(i + 1, len(string) - 2):
            if string[i:i+3] == string[j:j+3]:
                return False
    return True

def has_unique_chars_and_substrings(string):
    return has_unique_chars(string) and has_unique_substrings(string)

