def longest_substring(s):
    start = 0
    max_length = 0
    seen = {}
    for i in range(len(s)):
        if s[i] in seen and start <= seen[s[i]]:
            start = seen[s[i]] + 1
        else:
            max_length = max(max_length, i - start + 1)
        seen[s[i]] = i
    return max_length

def find_longest_substring(s):
    start = 0
    max_length = 0
    longest_start = 0
    longest_end = 0
    for i in range(len(s)):
        if s[i] in s[start:i]:
            if i - start >= max_length:
                max_length = i - start
                longest_start = start
                longest_end = i - 1
            start = i
    if len(s) - start >= max_length:
        max_length = len(s) - start
        longest_start = start
        longest_end = len(s) - 1
    return longest_start, longest_end

