import java.util.HashMap;

public class ReverseString {

    public static String reverseString(String str) {
        // Remove special characters
        String cleanedStr = str.replaceAll("[^a-zA-Z0-9]", "");

        // Convert numbers to Roman numerals
        cleanedStr = convertNumbersToRoman(cleanedStr);

        // Reverse the string
        StringBuilder reversedStr = new StringBuilder(cleanedStr);
        reversedStr.reverse();

        return reversedStr.toString();
    }

    public static boolean isPalindrome(String str) {
        // Remove special characters and convert numbers to Roman numerals
        String cleanedStr = reverseString(str);

        // Compare the reversed string with the original string
        return cleanedStr.equalsIgnoreCase(str);
    }

    public static String convertNumbersToRoman(String str) {
        HashMap<Character, Integer> romanNumerals = new HashMap<>();
        romanNumerals.put('I', 1);
        romanNumerals.put('V', 5);
        romanNumerals.put('X', 10);
        romanNumerals.put('L', 50);
        romanNumerals.put('C', 100);
        romanNumerals.put('D', 500);
        romanNumerals.put('M', 1000);

        StringBuilder convertedStr = new StringBuilder();
        for (char c : str.toCharArray()) {
            if (Character.isDigit(c)) {
                int num = Character.getNumericValue(c);
                convertedStr.append(convertToRoman(num));
            } else {
                convertedStr.append(c);
            }
        }

        return convertedStr.toString();
    }

    public static String convertToRoman(int num) {
        int[] values = {1000, 900, 500, 400, 100, 90, 50, 40, 10, 9, 5, 4, 1};
        String[] symbols = {"M", "CM", "D", "CD", "C", "XC", "L", "XL", "X", "IX", "V", "IV", "I"};

        StringBuilder romanNumeral = new StringBuilder();
        int i = 0;

        while (num > 0) {
            if (num >= values[i]) {
                romanNumeral.append(symbols[i]);
                num -= values[i];
            } else {
                i++;
            }
        }

        return romanNumeral.toString();
    }

    public static void main(String[] args) {
        String inputString = "Hello123!$%";

        String reversedString = reverseString(inputString);
        boolean isPalindrome = isPalindrome(inputString);

        System.out.println("Reversed String: " + reversedString);
        System.out.println("Is Palindrome: " + isPalindrome);
    }
}

