```javascript
// Initialize canvas
const canvas = document.getElementById('canvas');
const context = canvas.getContext('2d');
context.lineWidth = 1;
let drawing = false;
let actions = [];
let currentIndex = -1;
let color = '#000000';
let size = 5;
let fill = false;
let eraser = false;

// Functions to handle user actions
function startDraw(e) {
  drawing = true;
  context.beginPath();
  context.moveTo(e.clientX, e.clientY);
}

function draw(e) {
  if (!drawing) return;

  if (eraser) {
    context.globalCompositeOperation = 'destination-out';
    context.strokeStyle = 'rgba(0,0,0,1)';
  } else {
    context.globalCompositeOperation = 'source-over';
    context.strokeStyle = color;
  }

  context.lineTo(e.clientX, e.clientY);
  context.lineWidth = size;
  context.lineCap = 'round';
  context.lineJoin = 'round';
  context.stroke();
}

function endDraw() {
  if (!drawing) return;
  drawing = false;
  actions.push(context.getImageData(0, 0, canvas.width, canvas.height));
  currentIndex++;
}

function undo() {
  if (currentIndex <= 0) return;
  currentIndex--;
  context.putImageData(actions[currentIndex], 0, 0);
}

function redo() {
  if (currentIndex >= actions.length - 1) return;
  currentIndex++;
  context.putImageData(actions[currentIndex], 0, 0);
}

// Event listeners
canvas.addEventListener('mousedown', startDraw);
canvas.addEventListener('mousemove', draw);
canvas.addEventListener('mouseup', endDraw);

// Update drawing settings
document.getElementById('colorPicker').addEventListener('change', (e) => {
  color = e.target.value;
});

document.getElementById('sizePicker').addEventListener('change', (e) => {
  size = e.target.value;
});

document.getElementById('fillPicker').addEventListener('change', (e) => {
  fill = e.target.checked;
});

document.getElementById('eraser').addEventListener('change', (e) => {
  eraser = e.target.checked;
});
```

