Here's the C++ code that generates random numbers, sorts them, and calculates the sum, average, and standard deviation:

```cpp
#include <iostream>
#include <cstdlib>
#include <ctime>
#include <cmath>
#include <algorithm>

double calculateAverage(int arr[], int size) {
    double sum = 0;
    for (int i = 0; i < size; i++) {
        sum += arr[i];
    }
    return sum / size;
}

double calculateStandardDeviation(int arr[], int size, double average) {
    double sum = 0;
    for (int i = 0; i < size; i++) {
        sum += pow(arr[i] - average, 2);
    }
    return sqrt(sum / size);
}

int main() {
    const int size = 10;
    int numbers[size];

    // Generate random numbers between 1-100
    srand(time(0));
    for (int i = 0; i < size; i++) {
        numbers[i] = rand() % 100 + 1;
    }

    // Sort the array in ascending order
    std::sort(numbers, numbers + size);

    // Calculate sum, average, and standard deviation
    double sum = 0;
    for (int i = 0; i < size; i++) {
        sum += numbers[i];
    }
    double average = calculateAverage(numbers, size);
    double standardDeviation = calculateStandardDeviation(numbers, size, average);

    // Display the sorted array, sum, average, and standard deviation
    std::cout << "Sorted Array: ";
    for (int i = 0; i < size; i++) {
        std::cout << numbers[i] << " ";
    }
    std::cout << std::endl;
    std::cout << "Sum: " << sum << std::endl;
    std::cout << "Average: " << average << std::endl;
    std::cout << "Standard Deviation: " << standardDeviation << std::endl;

    return 0;
}
```

This code uses the `<ctime>` library to seed the random number generator, `<cstdlib>` library for generating random numbers, `<cmath>` library for calculating the square root and power, and `<algorithm>` library for sorting the array.

