    var targetColorValue = parseInt(targetColor.substring(4, targetColor.length - 1).split(", ")[0]);
    var newColorValue = Math.round(currentColorValue + (targetColorValue - currentColorValue) * progress);

    var newColor = "rgb(" + newColorValue + ", 0, 0)";

