<!DOCTYPE html>
<html>
<head>
  <title>Largest Prime Number</title>
  <script>
    // Check if a number is prime using Miller-Rabin primality test
    function isPrime(n) {
      // Base cases
      if (n <= 1) return false;
      if (n <= 3) return true;

      // Find r and odd part d such that n-1 = 2^r * d
      let d = n - 1;
      let r = 0;
      while (d % 2 === 0) {
        d /= 2;
        r++;
      }

      // Perform Miller-Rabin test k times
      const k = 5; // Number of tests
      for (let i = 0; i < k; i++) {
        const a = Math.floor(Math.random() * (n - 3)) + 2; // Random number between 2 and n-2
        let x = bigInt(a).modPow(bigInt(d), bigInt(n));
        if (x.equals(1) || x.equals(n - 1)) continue;

        let prime = false;
        for (let j = 0; j < r - 1; j++) {
          x = x.modPow(bigInt(2), bigInt(n));
          if (x.equals(n - 1)) {
            prime = true;
            break;
          }
        }

        if (!prime) return false;
      }

      return true;
    }

    // Find the largest prime number from the given list
    function findLargestPrime(numbers) {
      let largestPrime = -1;
      numbers.forEach(function (number) {
        if (isPrime(number) && number > largestPrime) {
          largestPrime = number;
        }
      });

      return largestPrime;
    }

