#include <stdio.h>

// Function to swap two elements
void swap(int* a, int* b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

// Function to partition the array
int partition(int arr[], int low, int high) {
    int pivot = arr[high];
    int i = (low - 1);

    for (int j = low; j <= high - 1; j++) {
        if (arr[j] < pivot) {
            i++;
            swap(&arr[i], &arr[j]);
        }
    }

    swap(&arr[i + 1], &arr[high]);
    return (i + 1);
}

// QuickSort function
void quickSort(int arr[], int low, int high) {
    if (low < high) {
        int pi = partition(arr, low, high);

        quickSort(arr, low, pi - 1);
        quickSort(arr, pi + 1, high);
    }
}

int main() {
    int size;
    printf("Enter the size of the array (between 1 and 100): ");
    scanf("%d", &size);

    if (size < 1 || size > 100) {
        printf("Invalid array size. Please try again.\n");
        return 0;
    }

    int arr[size];
    printf("Enter the elements of the array (between -1000 and 1000): ");
    for (int i = 0; i < size; i++) {
        scanf("%d", &arr[i]);
        if (arr[i] < -1000 || arr[i] > 1000) {
            printf("Invalid element. Please try again.\n");
            return 0;
        }
    }

    char order;
    printf("Enter 'A' for ascending order or 'D' for descending order: ");
    scanf(" %c", &order);

    if (order != 'A' && order != 'D') {
        printf("Invalid order selection. Please try again.\n");
        return 0;
    }

    // Sort the array using QuickSort
    quickSort(arr, 0, size - 1);

    // Print the sorted array
    printf("\nSorted array: ");
    if (order == 'A') {
        for (int i = 0; i < size; i++) {
            printf("%d ", arr[i]);
        }
    } else {
        for (int i = size - 1; i >= 0; i--) {
            printf("%d ", arr[i]);
        }
    }

    return 0;
}
```

This program takes the size of the array, the elements of the array, and the desired order (ascending or descending) as user inputs. It checks for invalid inputs and handles them accordingly. The program then uses the QuickSort algorithm to sort the array and displays the sorted array to the user.

Here's a Python code that generates Fibonacci numbers up to 10^8 using a while loop, and handles integer overflow as well as other exceptions:

```python
def fibonacci():
    a, b = 0, 1
    while a <= 10**8:
        yield a
        a, b = b, a + b

try:
    for num in fibonacci():
        print(num)
except OverflowError:
    print("An integer overflow occurred while calculating the Fibonacci numbers.")
except Exception as e:
    print("An error occurred:", e)
```

In this code, the `fibonacci()` function is a generator that yields Fibonacci numbers using a while loop. It starts with `a = 0` and `b = 1`, and in each iteration, it yields `a` and updates `a` and `b` to the next Fibonacci numbers.

The `try` block is used to catch any exceptions that may occur during the execution. If an `OverflowError` is raised, it means that the Fibonacci number has exceeded the limit of `10**8`, and an appropriate error message is printed. For any other exception, a generic error message along with the specific exception is displayed.

You can run this code to generate Fibonacci numbers up to 10^8 and see how it handles potential errors.
